-- 微调模型表
CREATE TABLE "public"."finetune_model"
(
    "id"                           int4                                         NOT NULL GENERATED BY DEFAULT AS IDENTITY (
        INCREMENT 1
MINVALUE  1
MAXVALUE 2147483647
START 1
CACHE 1
),
    "name"                         varchar(128) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "original_name"                varchar(255) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "classification"               int2                                         NOT NULL DEFAULT 1,
    "url"                          varchar(255) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "icon_url"                     varchar(300) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "path"                         varchar(300) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "options"                      jsonb                                        NOT NULL DEFAULT '[]'::jsonb,
    "introduction"                 varchar(255) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "unique_info"                  varchar(255) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "loading_mode"                 varchar(128) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "timbre_name"                  varchar(255) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "timbre_text"                  varchar(255) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "context_length"               int4                                         NOT NULL DEFAULT 0,
    "token_max"                    int4                                         NOT NULL DEFAULT 0,
    "overview"                     varchar(255) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "usage_scene"                  varchar(255) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "local_deploy"                 varchar(1024) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
    "api_document"                 varchar(1024) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
    "is_support_visual"            bool                                         NOT NULL DEFAULT false,
    "is_support_document"          bool                                         NOT NULL DEFAULT false,
    "is_support_function"          bool                                         NOT NULL DEFAULT false,
    "is_support_adjust"            bool                                         NOT NULL DEFAULT false,
    "train_status"                 int2                                         NOT NULL DEFAULT 0,
    "reason"                       varchar(1024) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
    "create_by"                    int4                                         NOT NULL DEFAULT 1,
    "update_by"                    int4                                         NOT NULL DEFAULT 1,
    "create_time"                  timestamp(0)                                 NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "update_time"                  timestamp(0)                                 NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "internal_name"                varchar(255) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "is_support_distributed_train" bool                                         NOT NULL DEFAULT false,
    "train_frame"                  varchar(255) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT 'PyTorch':: character varying,
    "config_text"                  text COLLATE "pg_catalog"."default"          NOT NULL DEFAULT ''::text,
    "dataset_id"                   int4                                         NOT NULL DEFAULT 0,
    "cpu_cores_num"                int4                                         NOT NULL DEFAULT 0,
    "memory_size"                  int4                                         NOT NULL DEFAULT 0,
    "is_selected_gpu"              bool                                         NOT NULL DEFAULT false,
    "gpu_num"                      int4                                         NOT NULL DEFAULT 0,
    "task_id"                      varchar(255) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    "code_dir"                     varchar(512) COLLATE "pg_catalog"."default"  NOT NULL DEFAULT '':: character varying,
    CONSTRAINT "finetune_model_pkey" PRIMARY KEY ("id")
)
;

ALTER TABLE "public"."finetune_model"
    OWNER TO "postgres";

COMMENT
ON COLUMN "public"."finetune_model"."id" IS '主键id';

COMMENT
ON COLUMN "public"."finetune_model"."name" IS '模型名称';

COMMENT
ON COLUMN "public"."finetune_model"."original_name" IS '模型原名称';

COMMENT
ON COLUMN "public"."finetune_model"."classification" IS '模型分类 1：文本生成；2：多模态；4：视频生成；5：图片生成；6：向量模型；7：语音合成；8：语音识别；9：排序模型；';

COMMENT
ON COLUMN "public"."finetune_model"."url" IS '模型调用地址';

COMMENT
ON COLUMN "public"."finetune_model"."icon_url" IS '图标地址';

COMMENT
ON COLUMN "public"."finetune_model"."path" IS '模型上传地址';

COMMENT
ON COLUMN "public"."finetune_model"."options" IS '模型配置';

COMMENT
ON COLUMN "public"."finetune_model"."introduction" IS '模型简介';

COMMENT
ON COLUMN "public"."finetune_model"."unique_info" IS '模型唯一信息';

COMMENT
ON COLUMN "public"."finetune_model"."loading_mode" IS '加载方式';

COMMENT
ON COLUMN "public"."finetune_model"."timbre_name" IS '音色名称';

COMMENT
ON COLUMN "public"."finetune_model"."timbre_text" IS '音色默认文本';

COMMENT
ON COLUMN "public"."finetune_model"."context_length" IS '模型上下文长度';

COMMENT
ON COLUMN "public"."finetune_model"."token_max" IS '最大tokens上限';

COMMENT
ON COLUMN "public"."finetune_model"."overview" IS '模型概述';

COMMENT
ON COLUMN "public"."finetune_model"."usage_scene" IS '应用场景';

COMMENT
ON COLUMN "public"."finetune_model"."local_deploy" IS '本地部署';

COMMENT
ON COLUMN "public"."finetune_model"."api_document" IS 'API调用文档';

COMMENT
ON COLUMN "public"."finetune_model"."is_support_visual" IS '是否支持视觉';

COMMENT
ON COLUMN "public"."finetune_model"."is_support_document" IS '是否支持文档';

COMMENT
ON COLUMN "public"."finetune_model"."is_support_function" IS '是否支持函数';

COMMENT
ON COLUMN "public"."finetune_model"."is_support_adjust" IS '是否支持微调';

COMMENT
ON COLUMN "public"."finetune_model"."train_status" IS '训练状态：0：训练中；1：排队中；2：训练成功；3：训练失败；';

COMMENT
ON COLUMN "public"."finetune_model"."reason" IS '失败原因';

COMMENT
ON COLUMN "public"."finetune_model"."create_by" IS '创建人';

COMMENT
ON COLUMN "public"."finetune_model"."update_by" IS '更新人';

COMMENT
ON COLUMN "public"."finetune_model"."create_time" IS '创建时间';

COMMENT
ON COLUMN "public"."finetune_model"."update_time" IS '更新时间';

COMMENT
ON COLUMN "public"."finetune_model"."internal_name" IS '模型内部名称';

COMMENT
ON COLUMN "public"."finetune_model"."is_support_distributed_train" IS '是否支持分布式训练';

COMMENT
ON COLUMN "public"."finetune_model"."train_frame" IS '分布式训练框架';

COMMENT
ON COLUMN "public"."finetune_model"."config_text" IS '配置文件脚本';

COMMENT
ON COLUMN "public"."finetune_model"."dataset_id" IS '数据集id';

COMMENT
ON COLUMN "public"."finetune_model"."cpu_cores_num" IS 'CPU核数';

COMMENT
ON COLUMN "public"."finetune_model"."memory_size" IS '内存（MB）';

COMMENT
ON COLUMN "public"."finetune_model"."is_selected_gpu" IS '是否选择GPU';

COMMENT
ON COLUMN "public"."finetune_model"."gpu_num" IS 'GPU块数';

COMMENT
ON COLUMN "public"."finetune_model"."task_id" IS '任务id';

COMMENT
ON COLUMN "public"."finetune_model"."code_dir" IS '解压后模型代码文件';


--微调模型分类
CREATE TABLE "public"."finetune_model_category"
(
    "id"          int4                                        NOT NULL GENERATED BY DEFAULT AS IDENTITY (
        INCREMENT 1
MINVALUE  1
MAXVALUE 2147483647
START 1
CACHE 1
),
    "name"        varchar(128) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
    "is_built"    bool                                        NOT NULL DEFAULT false,
    "create_by"   int4                                        NOT NULL DEFAULT 1,
    "update_by"   int4                                        NOT NULL DEFAULT 1,
    "create_time" timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "update_time" timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "finetune_model_category_pkey" PRIMARY KEY ("id")
)
;

ALTER TABLE "public"."finetune_model_category"
    OWNER TO "postgres";

COMMENT
ON COLUMN "public"."finetune_model_category"."id" IS '主键id';

COMMENT
ON COLUMN "public"."finetune_model_category"."name" IS '微调的模型分类名称';

COMMENT
ON COLUMN "public"."finetune_model_category"."is_built" IS '是否预设';

COMMENT
ON COLUMN "public"."finetune_model_category"."create_by" IS '创建人';

COMMENT
ON COLUMN "public"."finetune_model_category"."update_by" IS '更新人';

COMMENT
ON COLUMN "public"."finetune_model_category"."create_time" IS '创建时间';

COMMENT
ON COLUMN "public"."finetune_model_category"."update_time" IS '更新时间';

COMMENT
ON TABLE "public"."finetune_model_category" IS '微调模型分类';


--微调模型标签
CREATE TABLE "public"."finetune_model_tag"
(
    "id"                   int4                                        NOT NULL GENERATED BY DEFAULT AS IDENTITY (
        INCREMENT 1
MINVALUE  1
MAXVALUE 2147483647
START 1
CACHE 1
),
    "finetune_category_id" int4                                        NOT NULL DEFAULT 0,
    "name"                 varchar(128) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
    "create_by"            int4                                        NOT NULL DEFAULT 1,
    "update_by"            int4                                        NOT NULL DEFAULT 1,
    "create_time"          timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "update_time"          timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "finetune_model_tag_pkey" PRIMARY KEY ("id")
)
;

ALTER TABLE "public"."finetune_model_tag"
    OWNER TO "postgres";

COMMENT
ON COLUMN "public"."finetune_model_tag"."id" IS '主键id';

COMMENT
ON COLUMN "public"."finetune_model_tag"."finetune_category_id" IS '分类id';

COMMENT
ON COLUMN "public"."finetune_model_tag"."name" IS '标签名称';

COMMENT
ON COLUMN "public"."finetune_model_tag"."create_by" IS '创建人';

COMMENT
ON COLUMN "public"."finetune_model_tag"."update_by" IS '更新人';

COMMENT
ON COLUMN "public"."finetune_model_tag"."create_time" IS '创建时间';

COMMENT
ON COLUMN "public"."finetune_model_tag"."update_time" IS '更新时间';

COMMENT
ON TABLE "public"."finetune_model_tag" IS '微调模型标签';


--微调模型-标签关系
CREATE TABLE "public"."finetune_model_tag_relation"
(
    "id"                   int4         NOT NULL GENERATED BY DEFAULT AS IDENTITY (
        INCREMENT 1
MINVALUE  1
MAXVALUE 2147483647
START 1
CACHE 1
),
    "finetune_category_id" int4         NOT NULL DEFAULT 0,
    "finetune_tag_id"      int4         NOT NULL DEFAULT 0,
    "finetune_model_id"    int4         NOT NULL DEFAULT 0,
    "create_by"            int4         NOT NULL DEFAULT 1,
    "update_by"            int4         NOT NULL DEFAULT 1,
    "create_time"          timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "update_time"          timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "finetune_model_tag_relation_pkey" PRIMARY KEY ("id")
)
;

ALTER TABLE "public"."finetune_model_tag_relation"
    OWNER TO "postgres";

COMMENT
ON COLUMN "public"."finetune_model_tag_relation"."id" IS '主键id';

COMMENT
ON COLUMN "public"."finetune_model_tag_relation"."finetune_category_id" IS '分类id';

COMMENT
ON COLUMN "public"."finetune_model_tag_relation"."finetune_tag_id" IS '标签id';

COMMENT
ON COLUMN "public"."finetune_model_tag_relation"."finetune_model_id" IS '训练的模型id';

COMMENT
ON COLUMN "public"."finetune_model_tag_relation"."create_by" IS '创建人';

COMMENT
ON COLUMN "public"."finetune_model_tag_relation"."update_by" IS '更新人';

COMMENT
ON COLUMN "public"."finetune_model_tag_relation"."create_time" IS '创建时间';

COMMENT
ON COLUMN "public"."finetune_model_tag_relation"."update_time" IS '更新时间';

COMMENT
ON TABLE "public"."finetune_model_tag_relation" IS '微调模型-标签关系';


